import React from 'react';
import type {FieldValues} from 'react-hook-form';
import type {Shapes, UseFieldLogicElementProps} from "@lmb-it/kitsconcerto-types";
import {FormSelect} from "../../../../_compat";
import type {IListItem} from "@lmb-it/kitsconcerto-types";

export const Select = <T extends FieldValues>({
                                                  element,
                                                  control,
                                                  getValues,
                                                  fieldLogic,
                                              }: UseFieldLogicElementProps<T>) => {

    const {
        field,
        fieldState,
        label,
        placeholder,
        isDisabled,
        isRequired,
        helperText,
        watchedValues,
        list,
        attached,
        style: elementStyle,
        slots,
    } = fieldLogic;

    // Map form element type → FormSelect shape
    const shapeMap: Record<string, Shapes> = {
        Select: 'dropdown',
        Multiselect: 'multiselect',
        Tags: 'autocomplete',
        ListBox: 'listBox',
        TreeSelect: 'treeSelect',
    };

    const shape: Shapes = shapeMap[element.type as keyof typeof shapeMap] || 'dropdown';

    const {
        // Common
        labelKey,
        valueKey,
        outputValueKey,
        childrenKey,
        withFilter,
        filterBy,
        virtualScroll,
        // Specific
        withArrow,
        isMultiple,
        forceSelection,
        completeMethod,
        valueMode,
        selectionLimit,
        hideError,
        // TreeSelect specific
        onlyParentsWithChildren,
        isStructured,
    } = element as any;

    // No key regeneration needed here.
    // SelectContext already handles list changes reactively via its own useEffect([list]).
    // All underlying components (Dropdown, AutoComplete, etc.) react to prop changes natively.
    // A key change would force a full remount — destroying focus state and any user interaction.

    return (
        <FormSelect
            {...field}
            id={field.name}
            shape={shape}
            label={label}
            placeholder={placeholder}
            disabled={isDisabled}
            required={isRequired}
            invalid={fieldState.invalid}
            errors={fieldState.error?.message}
            helperText={helperText}
            list={list as IListItem[]}
            hideError={hideError}
            attached={attached}
            style={elementStyle?.input}
            containerStyle={elementStyle?.container}
            slots={slots}
            labelKey={labelKey}
            valueKey={valueKey}
            outputValueKey={outputValueKey}
            childrenKey={childrenKey}
            withFilter={withFilter}
            filterBy={filterBy}
            virtualScroll={virtualScroll}
            withArrow={withArrow}
            isMultiple={isMultiple}
            forceSelection={forceSelection}
            completeMethod={completeMethod}
            valueMode={valueMode}
            selectionLimit={selectionLimit}
            onlyParentsWithChildren={onlyParentsWithChildren}
            isStructured={isStructured}
        />
    );
};

export default Select;
